sql.where:
ubp.enabled = true

	and ub.bsns_year = #{bsnsYear}


	and ub.bsns_nm like concat('%', #{bsnsNm}, '%')


	and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')


	and ubp.pblanc_sttus_cd = #{pblancSttusCd}


	and ubp.ntce = #{ntce}


	and ubp.pblanc_id = #{pblancId}


	and ubp.rcept_bgnde >= #{rceptBgndeStart}


	and ubp.rcept_bgnde <= #{rceptBgndeEnd}


	and ubp.rcept_endde >= #{rceptEnddeStart}


	and ubp.rcept_endde <= #{rceptEnddeEnd}


	and ubp.pblanc_day >= #{pblancDayStart}


	and ubp.pblanc_day <= #{pblancDayEnd}


	and js.job_step_cd = #{jobStepCd}

mapper.select:
/** UsptBsnsPblancDao.selectAttachmentGroupId */
select
	ubp.attachment_group_id
from uspt_bsns_pblanc ubp
where
	ubp.pblanc_id = #{pblancId}

mapper.insert:
/** UsptBsnsPblancDao.insert */
insert into uspt_bsns_pblanc
					(
						pblanc_id
						, bsns_cd
						, pblanc_nm
						, pblanc_no
						, ordtm_rcrit
						, pblanc_day
						, bsns_bgnde
						, bsns_endde
						, bsns_scale
						, slctn_scale
						, pblanc_sumry
						, rcept_bgnde
						, rcept_endde
						, rcept_closing_hm
						, pblanc_sttus_cd
						, ntce
						, enabled
						, rdcnt
						, attachment_group_id
						, thumbnail_file_id
						, creator_id
						, created_dt
						, updater_id
						, updated_dt
					)
			values	(
						#{pblancId}
						, #{bsnsCd}
						, #{pblancNm}
						, #{pblancNo}
						, #{ordtmRcrit}
						, #{pblancDay}
						, #{bsnsBgnde}
						, #{bsnsEndde}
						, #{bsnsScale}
						, #{slctnScale}
						, #{pblancSumry}
						, #{rceptBgnde}
						, #{rceptEndde}
						, #{rceptClosingHm}
						, #{pblancSttusCd}
						, #{ntce}
						, #{enabled}
						, 0
						, #{attachmentGroupId}
						, #{thumbnailFileId}
						, #{creatorId}
						, #{createdDt}
						, #{updaterId}
						, #{updatedDt}
					)

mapper.update:
/** UsptBsnsPblancDao.update */
update uspt_bsns_pblanc
set
	updater_id 			= #{updaterId}
	, updated_dt 		= #{updatedDt}
	, pblanc_nm			= #{pblancNm}
	, pblanc_no			= #{pblancNo}
	, ordtm_rcrit		= #{ordtmRcrit}
	, pblanc_day		= #{pblancDay}
	, bsns_bgnde		= #{bsnsBgnde}
	, bsns_endde		= #{bsnsEndde}
	, bsns_scale		= #{bsnsScale}
	, slctn_scale		= #{slctnScale}
	, pblanc_sumry		= #{pblancSumry}
	, rcept_bgnde		= #{rceptBgnde}
	, rcept_endde		= #{rceptEndde}
	, rcept_closing_hm	= #{rceptClosingHm}
	, attachment_group_id = #{attachmentGroupId}

	, thumbnail_file_id = #{thumbnailFileId}

where
	pblanc_id = #{pblancId}

/** UsptBsnsPblancDao.updatePblancSttus */
update uspt_bsns_pblanc
set
	updater_id	 = #{updaterId}
	, updated_dt = #{updatedDt}
	, pblanc_sttus_cd = #{pblancSttusCd}
where
	pblanc_id = #{pblancId}

/** UsptBsnsPblancDao.updateNtce */
update uspt_bsns_pblanc
set
	updater_id	 = #{updaterId}
	, updated_dt = #{updatedDt}
	, ntce		 = #{ntce}
where
	pblanc_id = #{pblancId}

mapper.delete:
/** UsptBsnsPblancDao.updateUnable */
update uspt_bsns_pblanc
set
	updater_id	 = #{updaterId}
	, updated_dt = #{updatedDt}
	, enabled	 = #{enabled}
where
	pblanc_id = #{pblancId}

mapper.select:
/** UsptBsnsPblancDao.selectPblancListCount */ select count(ubp.pblanc_id) from uspt_bsns_pblanc ubp inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId}
and ubp.enabled = true and ubp.pblanc_sttus_cd != 'WAIT'
and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')

/** UsptBsnsPblancDao.selectPblancList */ select ubp.pblanc_id , ubp.pblanc_nm , ubpr.rcept_odr , ub.bsns_year , ub.bsns_nm , case when ubp.ordtm_rcrit = true then '상시모집' else '정시모집' end as ordtm_rcrit , row_number() over (order by ubp.created_dt desc) as rn from uspt_bsns_pblanc ubp inner join uspt_bsns_pblanc_rcept ubpr on ubpr.pblanc_id = ubp.pblanc_id inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_bsns_charger ubc on ubc.bsns_cd = ub.bsns_cd and ubc.insider_id = #{insiderId} left outer join uspt_slctn_pblanc usp on usp.pblanc_id = ubpr.pblanc_id and usp.rcept_odr = ubpr.rcept_odr
ubp.enabled = true and ubp.pblanc_sttus_cd != 'WAIT' and usp.slctn_pblanc_id is null
and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')
offset #{beginRowNum} -1 limit #{itemsPerPage}

/** UsptBsnsPblancDao.selectFrontListCount */ select count(*) from ( select ubp.pblanc_id from uspt_bsns_pblanc ubp inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd left outer join uspt_bsns_recomend_cl ubrc on ubrc.bsns_cd = ub.bsns_cd and ubrc.recomend_cl_type_cd = '${@aicluster.pms.common.util.Code@RC_BSR}' left outer join uspt_bsns_apply_mber_type ubamt on ubamt.bsns_cd = ub.bsns_cd where ubp.enabled = true and ubp.ntce = true and ubp.ordtm_rcrit = #{ordtmRcrit} and ubp.rcept_endde >= to_char(now(), 'yyyymmdd')
and ubp.pblanc_sttus_cd in
#{item}
and ubamt.apply_mber_type_cd in
#{item}
and ubrc.recomend_cl_cd in
#{item}
and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')
group by ubp.pblanc_id ) sub

/** UsptBsnsPblancDao.selectFrontList */ select sub.* from ( select ubp.pblanc_id , ubp.pblanc_nm , ubp.pblanc_day , ubp.pblanc_sumry , ubp.rdcnt , ubp.pblanc_sttus_cd , fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@PS_CODE_GROUP}', ubp.pblanc_sttus_cd) as pblanc_sttus , (ubp.rcept_endde::date - to_char(now(), 'yyyymmdd')::date) as rmndr_day , ubp.rcept_endde , concat(to_char(to_date(ubp.rcept_bgnde,'yyyymmdd'), 'yyyy-mm-dd' ) , ' ~ ' , to_char(to_date(ubp.rcept_endde,'yyyymmdd'), 'yyyy-mm-dd' ) , ' ' , ubp.rcept_closing_hm, ':00' ) as rcept_pd , array_to_string(array_agg(distinct fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@RC_CODE_GROUP}', ubrc.recomend_cl_cd)), ',') as recomend_cl , case when cast(to_char(now() , 'yyyymmddhh24miss') as bigint) - cast(to_char(ubp.created_dt , 'yyyymmddhh24miss') as bigint) <= 240000 then 'Y' else 'N' end as is_new , lag(ubp.pblanc_id, 1) over(
order by ubp.pblanc_day order by ubp.rcept_endde order by ubp.rdcnt desc order by ubp.pblanc_day ) as pre_pblanc_id , lag(ubp.pblanc_nm, 1, '이전 공고가 없습니다.') over(
order by ubp.pblanc_day order by ubp.rcept_endde order by ubp.rdcnt desc order by ubp.pblanc_day ) as pre_pblanc_nm , lead (ubp.pblanc_id,1) over (
order by ubp.pblanc_day order by ubp.rcept_endde order by ubp.rdcnt desc order by ubp.pblanc_day ) as next_pblanc_id , lead (ubp.pblanc_nm,1, '다음 공고가 없습니다.') over (
order by ubp.pblanc_day order by ubp.rcept_endde order by ubp.rdcnt desc order by ubp.pblanc_day ) as next_pblanc_nm from uspt_bsns_pblanc ubp inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd left outer join uspt_bsns_recomend_cl ubrc on ubrc.bsns_cd = ub.bsns_cd and ubrc.recomend_cl_type_cd = '${@aicluster.pms.common.util.Code@RC_BSR}' left outer join uspt_bsns_apply_mber_type ubamt on ubamt.bsns_cd = ub.bsns_cd where ubp.enabled = true and ubp.ntce = true and ubp.ordtm_rcrit = #{ordtmRcrit} and ubp.rcept_endde >= to_char(now(), 'yyyymmdd')
and (ubp.rcept_endde::date - to_char(now(), 'yyyymmdd')::date) <= 7
and ubp.pblanc_sttus_cd in
#{item}
and ubamt.apply_mber_type_cd in
#{item}
and ubrc.recomend_cl_cd in
#{item}
and ubp.pblanc_nm like concat('%', #{pblancNm}, '%')
group by ubp.pblanc_id
order by ubp.pblanc_day order by ubp.rcept_endde order by ubp.rdcnt desc order by ubp.pblanc_day
offset #{beginRowNum} -1 limit #{itemsPerPage}
) sub
and pblanc_id = #{pblancId}

mapper.update:
/** UsptBsnsPblancDao.updateRdcnt */
update uspt_bsns_pblanc
set
	rdcnt = (select rdcnt + 1 from uspt_bsns_pblanc where pblanc_id = #{pblancId})
where
	pblanc_id = #{pblancId}

mapper.select:
/** UsptBsnsPblancDao.selectFrontMainRecomendList */ select sub.* , row_number() over (order by sub.rmndr_day) as rn from ( select ubp.pblanc_id , ubp.pblanc_nm , (ubp.rcept_endde::date - to_char(now(), 'yyyymmdd')::date) as rmndr_day , concat(to_char(to_date(ubp.rcept_bgnde,'yyyymmdd'), 'yyyy-mm-dd' ) , ' ~ ' , to_char(to_date(ubp.rcept_endde,'yyyymmdd'), 'yyyy-mm-dd' ) , ' ' , ubp.rcept_closing_hm, ':00' ) as rcept_pd , array_to_string(array_agg(distinct fn_cmm_get_code_nm('${@aicluster.pms.common.util.Code@RC_CODE_GROUP}', ubrc.recomend_cl_cd)), ',') as recomend_cl from uspt_bsns_pblanc ubp inner join uspt_bsns ub on ub.bsns_cd = ubp.bsns_cd inner join uspt_bsns_recomend_cl ubrc on ubrc.bsns_cd = ub.bsns_cd and ubrc.recomend_cl_type_cd = '${@aicluster.pms.common.util.Code@RC_BSR}' inner join uspt_bsns_recomend_cl ubrc1 on ubrc1.bsns_cd = ub.bsns_cd and ubrc1.recomend_cl_type_cd = '${@aicluster.pms.common.util.Code@RC_FNTN}' where ubp.enabled = true and ubp.ntce = true and ubp.rcept_endde >= to_char(now(), 'yyyymmdd') and ubp.pblanc_sttus_cd IN ('${@aicluster.pms.common.util.Code@PS_WAIT_CODE}', '${@aicluster.pms.common.util.Code@PS_ING_CODE}' )
and ubrc.recomend_cl_cd in
#{item}
and ubrc1.recomend_cl_cd = #{fntnRecomendClCd}
group by ubp.pblanc_id ) sub order by sub.rmndr_day limit 16

/** UsptBsnsPblancDao.selectPblancNoCount */
select
	count(*)
from uspt_bsns_pblanc
where
	pblanc_no = #{pblancNo}
